export type ChatCommandSurface = "web" | "ide";

export type ChatSlashCommandId =
  | "image"
  | "skill"
  | "agent-create"
  | "agent-spawn"
  | "spec"
  | "design"
  | "tasks";

export type IdeSpecSlashCommandId = "spec" | "design" | "tasks";

export interface ChatSlashCommandDefinition {
  id: ChatSlashCommandId;
  label: string;
  description: string;
  descriptionI18nKey?: string;
  insert: string;
  surfaces: ChatCommandSurface[];
}

export interface ChatSlashCommand {
  label: string;
  description: string;
  insert: string;
}

export interface AgentSlashCommandSource {
  id: string;
  description: string;
}

