export function parseSlashQuery(content: string): string {
  const trimmed = content.trimStart();
  if (!trimmed.startsWith("/") || trimmed.includes("\n")) return "";
  return trimmed.slice(1).toLowerCase();
}

export function slashMenuShouldOpen(content: string, commandCount: number): boolean {
  const trimmed = content.trimStart();
  return trimmed === "/" || (trimmed.startsWith("/") && !trimmed.includes("\n") && commandCount > 0);
}

function matchesSlashQuery(label: string, slashQuery: string): boolean {
  if (!slashQuery) return true;
  return label.slice(1).toLowerCase().startsWith(slashQuery);
}

export function buildChatSlashCommands(options: {
  surface: ChatCommandSurface;
  agents?: AgentSlashCommandSource[];
  slashQuery?: string;
  translate?: (key: string) => string;
}): ChatSlashCommand[] {
  const { surface, agents = [], slashQuery = "", translate } = options;
  const resolveDescription = (definition: ChatSlashCommandDefinition) => {
    if (translate && definition.descriptionI18nKey) {
      return translate(definition.descriptionI18nKey);
    }
    return definition.description;
  };

  const staticCommands = CHAT_SLASH_COMMAND_DEFINITIONS.filter((definition) => definition.surfaces.includes(surface)).map(
    (definition) => ({
      label: definition.label,
      description: resolveDescription(definition),
      insert: definition.insert,
    }),
  );

  const agentCommands =
    surface === "web" || surface === "ide"
      ? agents.map((agent) => ({
          label: `/agent spawn ${agent.id}`,
          description: agent.description,
          insert: `/agent spawn ${agent.id} `,
        }))
      : [];

  return [...staticCommands, ...agentCommands].filter((command) => matchesSlashQuery(command.label, slashQuery));
}

export function isChatSlashCommand(content: string, command: ChatSlashCommandId): boolean {
  const normalized = content.trimStart().toLowerCase();
  switch (command) {
    case "image":
      return normalized.startsWith("/image");
    case "skill":
      return normalized.startsWith("/skill");
    case "agent-create":
      return normalized.startsWith("/agent create");
    case "agent-spawn":
      return normalized.startsWith("/agent spawn") || normalized.startsWith("/agent run");
    case "spec":
      return normalized.startsWith("/spec");
    case "design":
      return normalized.startsWith("/design");
    case "tasks":
      return normalized.startsWith("/tasks");
    default:
      return false;
  }
}

/** @deprecated Use isChatSlashCommand with "skill" */
export function isSkillSlashCommand(content: string): boolean {
  return isChatSlashCommand(content, "skill");
}

/** @deprecated Use isChatSlashCommand with "agent-create" or "agent-spawn" */
export function isAgentSlashCommand(content: string): boolean {
  const normalized = content.trimStart().toLowerCase();
  return normalized.startsWith("/agent");
}

/** @deprecated Use isChatSlashCommand with "image" */
export function isImageSlashCommand(content: string): boolean {
  return isChatSlashCommand(content, "image");
}

export function detectIdeSpecSlashCommand(content: string): { command?: IdeSpecSlashCommandId; rest: string } {
  const trimmed = content.trimStart();
  const match = trimmed.match(/^\/(spec|design|tasks)(\s|$)/);
  if (!match) return { rest: content };
  return {
    command: match[1] as IdeSpecSlashCommandId,
    rest: trimmed.slice(match[0].length).trimStart(),
  };
}
